-- ============================================================================
-- catalog_pivot.sql - storefront catalog for the Cycle Store demo.
-- Idempotent: safe to re-run. Applied after the base CYCLE_STORE schema load.
--   * 6 new subcategories (Sunglasses/Protectors/Backpacks/Bells/Tools/Shoes)
--   * moves Helmets under Clothing
--   * 114 curated products (ProductID 1000-1113)
--   * removes duplicate size-variants from the original AdventureWorks rows
-- ============================================================================
USE CYCLE_STORE;
SET NOCOUNT ON;
GO

-- 1. New subcategories -------------------------------------------------------
IF NOT EXISTS (SELECT 1 FROM Production.ProductSubcategory WHERE ProductSubcategoryID=38) INSERT INTO Production.ProductSubcategory (ProductSubcategoryID,ProductCategoryID,Name,rowguid,ModifiedDate) VALUES (38,3,N'Sunglasses',NEWID(),GETDATE());
IF NOT EXISTS (SELECT 1 FROM Production.ProductSubcategory WHERE ProductSubcategoryID=39) INSERT INTO Production.ProductSubcategory (ProductSubcategoryID,ProductCategoryID,Name,rowguid,ModifiedDate) VALUES (39,3,N'Protectors',NEWID(),GETDATE());
IF NOT EXISTS (SELECT 1 FROM Production.ProductSubcategory WHERE ProductSubcategoryID=40) INSERT INTO Production.ProductSubcategory (ProductSubcategoryID,ProductCategoryID,Name,rowguid,ModifiedDate) VALUES (40,3,N'Backpacks',NEWID(),GETDATE());
IF NOT EXISTS (SELECT 1 FROM Production.ProductSubcategory WHERE ProductSubcategoryID=41) INSERT INTO Production.ProductSubcategory (ProductSubcategoryID,ProductCategoryID,Name,rowguid,ModifiedDate) VALUES (41,2,N'Bells',NEWID(),GETDATE());
IF NOT EXISTS (SELECT 1 FROM Production.ProductSubcategory WHERE ProductSubcategoryID=42) INSERT INTO Production.ProductSubcategory (ProductSubcategoryID,ProductCategoryID,Name,rowguid,ModifiedDate) VALUES (42,4,N'Tools',NEWID(),GETDATE());
IF NOT EXISTS (SELECT 1 FROM Production.ProductSubcategory WHERE ProductSubcategoryID=43) INSERT INTO Production.ProductSubcategory (ProductSubcategoryID,ProductCategoryID,Name,rowguid,ModifiedDate) VALUES (43,3,N'Shoes',NEWID(),GETDATE());

-- 2. Move Helmets from Accessories to Clothing -------------------------------
UPDATE Production.ProductSubcategory SET ProductCategoryID=3 WHERE ProductSubcategoryID=31;
GO

