-- 4. De-duplicate original AdventureWorks size-variants (keep one per model) --
;WITH b AS (
  SELECT ProductID, Name,
    CASE WHEN CHARINDEX(',', Name)>0 THEN RTRIM(LEFT(Name, LEN(Name)-CHARINDEX(',', REVERSE(Name)))) ELSE Name END AS Base
  FROM Production.Product WHERE ProductID < 1000
),
r AS (SELECT ProductID, ROW_NUMBER() OVER (PARTITION BY Base ORDER BY ProductID) rn FROM b)
DELETE FROM Production.Product WHERE ProductID IN (SELECT ProductID FROM r WHERE rn>1);
GO
